import React from 'react';
import "./App.css"
import {Provider} from 'react-redux';
import {store} from '../src/redux/store'
import Home from "./components/home/Home";
import {BrowserRouter as Router , Route , Switch} from 'react-router-dom';
import ProductList from "./components/product/ProductList";
import ProductAdmin from "./components/product/ProductAdmin";
import CreateProduct from "./components/product/CreateProduct";
import UpdateProduct from "./components/product/UpdateProduct";
import Navbar from "./components/navbar/Navbar";

let App = ()=>{


    return (
        <React.Fragment>
            <Router>
                <Provider store={store}>
                    <Navbar/>
                    <Switch>
                        <Route exact path='/' component={Home}/>
                        <Route exact path='/products/list' component={ProductList}/>
                        <Route exact path='/products/admin' component={ProductAdmin}/>
                        <Route exact path='/products/create' component={CreateProduct}/>
                        <Route exact path='/products/:id' component={UpdateProduct}/>
                    </Switch>
                </Provider>
            </Router>

        </React.Fragment>
    );
};


export default App;
