import * as bigBasketActions  from './bigBasket.actions';

// features kay
export  const bigBasketFeaturesKey = 'bigBasket';

//initial state
let initialState = {
    loading : false,
    products : [],
    singleProduct : {},
    errorMessage : ''
};

//reducer function

export const reducer =(state = initialState  , action)=>{
    let {type , payload} = action;
    switch (type){
        //fetch all product
        case bigBasketActions.FETCH_ALL_PRODUCTS_REQUEST:
            return{
                ...state,
                loading:true,
            };
        case bigBasketActions.FETCH_ALL_PRODUCTS_SUCCESS:
            return{
                ...state,
                loading:false,
                products:payload
            };
        case bigBasketActions.FETCH_ALL_PRODUCTS_FAILURE:
            return{
                ...state,
                loading:false,
                errorMessage:payload
            };

            // fetch single product
        case bigBasketActions.FETCH_SINGLE_PRODUCTS_REQUEST:
            return{
                ...state,
                loading:true,
            };
        case bigBasketActions.FETCH_SINGLE_PRODUCTS_SUCCESS:
            return{
                ...state,
                loading:false,
                singleProduct:payload
            };
        case bigBasketActions.FETCH_SINGLE_PRODUCTS_FAILURE:
            return{
                ...state,
                loading:false,
                errorMessage:payload
            };

            //create a product
        case bigBasketActions.CREATE_NEW_PRODUCTS_REQUEST:
            return{
                ...state,
                loading:true,
            };
        case bigBasketActions.CREATE_NEW_PRODUCTS_SUCCESS:
            return{
                ...state,
                loading:false,
            };
        case bigBasketActions.CREATE_NEW_PRODUCTS_FAILURE:
            return{
                ...state,
                loading:false,
            };

            //update product
        case bigBasketActions.UPDATE_PRODUCTS_REQUEST:
            return{
                ...state,
                loading: true
            };
        case bigBasketActions.UPDATE_PRODUCTS_SUCCESS:
            return{
                ...state,
                loading : false
            };
        case bigBasketActions.UPDATE_PRODUCTS_FAILURE:
            return{
                ...state,
                loading:false
            };

        //update product
        case bigBasketActions.DELETE_PRODUCTS_REQUEST:
            return{
                ...state,
                loading: true
            };
        case bigBasketActions.DELETE_PRODUCTS_SUCCESS:
            return{
                ...state,
                loading : false,
            };
        case bigBasketActions.DELETE_PRODUCTS_FAILURE:
            return{
                ...state,
                loading:false
            };

            //update from input
        case bigBasketActions.UPDATE_INPUT:
            return {
                ...state,
                singleProduct: {
                    ...state.singleProduct,
                    [payload.key] : payload.value
                }
            };

        default:return state;

    }
};