import  React,{useEffect} from 'react';
import {useDispatch , useSelector} from 'react-redux';
import * as bigBaskerActions from '../../redux/bigBasket/bigBasket.actions';
import * as bigBasketReducer from '../../redux/bigBasket/bigBasket.reducer';
import spinner from '../../assets/image/spinner.gif';

let ProductList = ()=>{

    //dispatch action
    let dispatch = useDispatch();
    useEffect(()=>{
        dispatch(bigBaskerActions.fetchAllProducts());
    },[]);

    // get data from redux store
    let productsInfo = useSelector((state)=>{
        return state[bigBasketReducer.bigBasketFeaturesKey];
    });
    let {loading , products , errormessage} = productsInfo;

    return(
        <React.Fragment>
            <div className="container mt-3">
                <div className="row">
                    <div className="col">
                        <p className="h3 text-secondary">Product List</p>
                        <p className="lead">Lorem ipsum dolor sit amet, consectetur adipisicing elit. Adipisci at blanditiis cum, debitis dicta distinctio dolorum eligendi error, illum minima molestias natus numquam quae quis quisquam, quod soluta tempore veniam. Architecto et hic inventore iure iusto. Dolores enim error voluptas.</p>
                    </div>
                </div>
                <div className="row">

                    {
                        loading ?
                            <React.Fragment>
                                <img src={spinner} className="d-block m-auto" alt=""/>
                            </React.Fragment> :
                            <React.Fragment>
                                {
                                    products.length > 0 ?
                                        <React.Fragment>
                                            {
                                                products.map((product)=>{
                                                    return(
                                                        <div className="col-md-3">
                                                            <div className="card mt-3">
                                                                <div className="card-header bg-white text-center">
                                                                    <img src={product.image} width="150"  height="150" />
                                                                </div>
                                                                <div className="card-body">
                                                                    <ul className="list-group">
                                                                        <li className="list-group-item">
                                                                            Name:{product.name}
                                                                        </li>

                                                                        <li className="list-group-item">
                                                                            Price: &#8377;{product.price.toFixed(2)}
                                                                        </li>

                                                                        <li className="list-group-item">
                                                                            Qty:{product.qty} Kgs
                                                                        </li>
                                                                    </ul>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    )
                                                })
                                            }
                                        </React.Fragment> : null
                                }
                            </React.Fragment>
                    }

                </div>
            </div>
        </React.Fragment>
    )
};
export  default ProductList;