import  React ,{useState} from 'react';
import {useDispatch} from 'react-redux';
import {useHistory} from 'react-router-dom';
import * as bigBasketAction  from '../../redux/bigBasket/bigBasket.actions';

let CreateProduct = ()=>{

    let [product , setProduct] = useState({
        name:'',
        image:'',
        price:'',
        qty:'',
        info:''
    });

    //updateInput
    let updateInput=(event)=>{
        setProduct({
            ...product,
            [event.target.name] : event.target.value
        });
    };

    // updateImage function
    let  updateImage = async (event) => {
        let imageFile = event.target.files[0];
        let base64Image = await convertBase64String(imageFile);
        setProduct({
            ...product,
            image : base64Image
        });
    };

    //convert image to base64 format
    let convertBase64String = (imageFile)=>{
        return new Promise((resolve , reject)=>{
            let fileReader = new FileReader();
            fileReader.readAsDataURL(imageFile);
            fileReader.addEventListener('load', ()=>{
                if(fileReader.result){
                    resolve(fileReader.result);
                }
                else {
                    reject('Error Occurred');
                }
            })
        });
    };



    //form submit | create new product
    let dispatch = useDispatch();
    let history = useHistory();

    let submitProduct = (event) =>{
        event.preventDefault();
        dispatch(bigBasketAction.createNewProduct(history , product));
    };



    return(
            <React.Fragment>
                <div className="container mt-3">
                    <div className="row">
                        <div className="col">
                            <p className="h3 ">Create New Product</p>
                            <p className="lead">Lorem ipsum dolor sit amet, consectetur adipisicing elit. Asperiores
                                consectetur exercitationem illo incidunt iste perspiciatis, tempore? Animi corporis
                                earum esse, expedita itaque, officiis omnis porro praesentium quibusdam quidem totam
                                unde?</p>
                        </div>
                    </div>
                    <div className="row">
                        <div className="col-md-6">
                            <div className="card">
                                <div className="card-header bg-secondary text-white">
                                    <h3>Create a New Product</h3>
                                </div>
                                <div className="card-body rgba-purple-light">
                                    <form onSubmit={submitProduct}>
                                        <div className="form-group">
                                            <input
                                                name="name"
                                                value={product.name}
                                                onChange={updateInput}
                                                required type="text" className="form-control"
                                                placeholder="Product Name"/>
                                        </div>
                                        <div className="form-group">
                                            <div className="custom-file">
                                                <input
                                                    onChange={updateImage}
                                                    type="file" className="custom-file-input"
                                                    id="customFile"/>
                                                <label className="custom-file-label" htmlFor="customFile">
                                                    {
                                                        product.image !== '' ?
                                                            <img src={product.image} alt=""
                                                                 width="30" height="30"/> :
                                                                    <span>Product Image</span>
                                                    }
                                                    </label>
                                            </div>
                                        </div>
                                        <div className="form-group">
                                            <input
                                                name="price"
                                                value={product.price}
                                                onChange={updateInput}
                                                required type="number" className="form-control"
                                                placeholder="Product Price"/>
                                        </div>
                                        <div className="form-group">
                                            <input
                                                name="qty"
                                                value={product.qty}
                                                onChange={updateInput}
                                                required type="number" className="form-control"
                                                placeholder="Available Quantity"/>
                                        </div>
                                        <div className="form-group">
                                            <textarea
                                                name="info"
                                                value={product.info}
                                                onChange={updateInput}
                                                required className="form-control" rows="4"
                                                placeholder="Product Info"/>
                                        </div>
                                        <div>
                                            <input type="submit" className="btn btn-secondary btn-sm"
                                                   value="create"/>
                                        </div>
                                    </form>
                                    <small className="mt-5"> Note:-Please don't Upload any ugly product</small>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </React.Fragment>
    )
};
export  default CreateProduct;