import React, {useEffect} from 'react';
import {Link} from 'react-router-dom';
import {useSelector , useDispatch} from 'react-redux';
import Axios from "axios/index";
import * as bigBaskerActions from "../../redux/bigBasket/bigBasket.actions";
import * as bigBasketReducer from "../../redux/bigBasket/bigBasket.reducer";
import  spinner from "../../assets/image/spinner.gif";

let ProductAdmin = ()=>{


    //dispatch action
    let dispatch = useDispatch();
    useEffect(()=>{
        dispatch(bigBaskerActions.fetchAllProducts());
    },[]);

    // get data from redux store
    let productsInfo = useSelector((state)=>{
        return state[bigBasketReducer.bigBasketFeaturesKey];
    });
    let {loading , products , errormessage} = productsInfo;

// delete product
let deleteProduct = (productId)=>{
    dispatch(bigBaskerActions.deleteProduct(productId));

};

    return(
        <React.Fragment>
           <div className="container mt-3">
               <div className="row">
                   <div className="col animated zoomIn">
                       <p className="h3">Product Admin</p>
                       <p className="lead">Lorem ipsum dolor sit amet, consectetur adipisicing elit. Cumque eaque itaque repudiandae saepe temporibus? Ad cupiditate eum incidunt inventore ipsa magnam minima recusandae rem ullam ut? Aut, beatae, distinctio et excepturi, incidunt iure necessitatibus possimus provident sequi soluta unde vero?</p>
                       <Link to='/products/create' className="btn btn-secondary btn-sm">Create New</Link>
                   </div>
               </div>

               {
                   loading ?
                       <React.Fragment>
                           <img src={spinner} className="d-block m-auto" alt=""/>
                       </React.Fragment> :
                       <div className="row mt-3">
                           <div className="col animated zoomInUp ">
                               <table className="table table-hover table-striped text-center bg-light">
                                   <thead className="bg-secondary">
                                   <tr>
                                       <th>Sno.</th>
                                       <th>Image</th>
                                       <th>Name</th>
                                       <th>Price</th>
                                       <th>Qty</th>
                                       <th>Action</th>
                                   </tr>
                                   </thead>
                                   <tbody>
                                   {
                                       products.length > 0 ?
                                           <React.Fragment>
                                               {
                                                   products.map((product)=>{
                                                       return(
                                                           <tr key={product._id}>
                                                               <td>{product._id.substr(product._id.length-4)}</td>
                                                               <td><img src={product.image} width="100"  height="100"/></td>
                                                               <td>{product.name}</td>
                                                               <td>&#8377;{product.price.toFixed(2)}</td>
                                                               <td>{product.qty} Kgs</td>
                                                               <Link to={`/products/${product._id}`} className="btn btn-primary btn-sm">Update</Link>
                                                               <button onClick={deleteProduct.bind(this , product._id)} className="btn btn-danger btn-sm">Delete</button>
                                                           </tr>
                                                       )
                                                   })
                                               }
                                           </React.Fragment> : <React.Fragment>
                                               <tr>
                                                   <td colSpan="6" className="text-danger font-weight-bold">----------- No Products Found --------- </td>
                                               </tr>
                                           </React.Fragment>
                                   }
                                   </tbody>
                               </table>
                           </div>
                       </div>
               }

           </div>
        </React.Fragment>
    )
};
export  default ProductAdmin;