import  Axios from 'axios';

//ACTION TYPES FOR

export  const UPDATE_INPUT = 'UPDATE_INPUT';

// fetch all the products
export  const FETCH_ALL_PRODUCTS_REQUEST = 'FETCH_ALL_PRODUCTS_REQUEST';
export  const FETCH_ALL_PRODUCTS_SUCCESS = 'FETCH_ALL_PRODUCTS_SUCCESS';
export  const FETCH_ALL_PRODUCTS_FAILURE = 'FETCH_ALL_PRODUCTS_FAILURE';


//fetch a single product
export  const FETCH_SINGLE_PRODUCTS_REQUEST = 'FETCH_SINGLE_PRODUCTS_REQUEST';
export  const FETCH_SINGLE_PRODUCTS_SUCCESS = 'FETCH_SINGLE_PRODUCTS_SUCCESS';
export  const FETCH_SINGLE_PRODUCTS_FAILURE = 'FETCH_SINGLE_PRODUCTS_FAILURE';


//CREATE a NEW product
export  const CREATE_NEW_PRODUCTS_REQUEST = 'CREATE_NEW_PRODUCTS_REQUEST';
export  const CREATE_NEW_PRODUCTS_SUCCESS = 'CREATE_NEW_PRODUCTS_SUCCESS';
export  const CREATE_NEW_PRODUCTS_FAILURE = 'CREATE_NEW_PRODUCTS_FAILURE';


//UPDATE a  product
export  const UPDATE_PRODUCTS_REQUEST = 'UPDATE_PRODUCTS_REQUEST';
export  const UPDATE_PRODUCTS_SUCCESS = 'UPDATE_PRODUCTS_SUCCESS';
export  const UPDATE_PRODUCTS_FAILURE = 'UPDATE_PRODUCTS_FAILURE';


//DELETE a  product
export  const DELETE_PRODUCTS_REQUEST = 'DELETE_PRODUCTS_REQUEST';
export  const DELETE_PRODUCTS_SUCCESS = 'DELETE_PRODUCTS_SUCCESS';
export  const DELETE_PRODUCTS_FAILURE = 'DELETE_PRODUCTS_FAILURE';

// get all products function
export  const fetchAllProducts = ()=>{
    return async (dispatch)=>{
        try {
            dispatch({type : FETCH_ALL_PRODUCTS_REQUEST});
            let dataURL = `${process.env.REACT_APP_EXPRESS_SERVER}/api/products`;
            let response = await Axios.get(dataURL);
            dispatch({type : FETCH_ALL_PRODUCTS_SUCCESS , payload : response.data});
        }
        catch (error) {
            dispatch({type : FETCH_ALL_PRODUCTS_FAILURE , payload: error});
        }
    };
};

// get a single product
export  const getSingleProduct = (productId)=>{
    return  async(dispatch)=>{
        try {
            dispatch({type : FETCH_SINGLE_PRODUCTS_REQUEST});
            let dataURL = `${process.env.REACT_APP_EXPRESS_SERVER}/api/products/${productId}`;
            let response = await Axios.get(dataURL);
            dispatch({type : FETCH_SINGLE_PRODUCTS_SUCCESS , payload : response.data});
        }
        catch (error) {
            dispatch({type : FETCH_SINGLE_PRODUCTS_FAILURE , payload : error});
        }
    };
};



//create new products
export const createNewProduct = (history , product)=>{
    return async (dispatch)=>{
        try {
            dispatch({type : CREATE_NEW_PRODUCTS_REQUEST});
            let dataURL = `${process.env.REACT_APP_EXPRESS_SERVER}/api/products/`;
            let response = await Axios.post(dataURL , product);
            dispatch({type : CREATE_NEW_PRODUCTS_SUCCESS , payload : response.data});
            //redirect to admin page
            history.push('/products/admin');
        }catch (error) {
            dispatch({type : CREATE_NEW_PRODUCTS_FAILURE , payload : error})
        }
    }
};

// update a Product
export const updateProduct = (productId, product , history) => {
    return async (dispatch) => {
        try {
            dispatch({type : UPDATE_PRODUCTS_REQUEST});
            let dataURL = `${process.env.REACT_APP_EXPRESS_SERVER}/api/products/${productId}`;
            let response = await Axios.put(dataURL , product);
            dispatch({type : UPDATE_PRODUCTS_SUCCESS , payload : response.data});
            history.push('/products/admin');
        }
        catch (error){
            dispatch({type : UPDATE_PRODUCTS_FAILURE , payload : error});
        }
    }
};


// delete a Product
export const deleteProduct = (productId) => {
    return async (dispatch) => {
        try {
            dispatch({type : DELETE_PRODUCTS_REQUEST});
            let dataURL = `${process.env.REACT_APP_EXPRESS_SERVER}/api/products/${productId}`;
            let response = await Axios.delete(dataURL);
            dispatch({type : DELETE_PRODUCTS_SUCCESS , payload : response.data});
            dispatch(fetchAllProducts());
        }
        catch (error){
            dispatch({type : DELETE_PRODUCTS_FAILURE , payload : error});
        }
    }
};





// updateFormInput
export const updateFormInput = (key , value) => {
    return {
        type : UPDATE_INPUT,
        payload : {key , value}
    }
};

